 1	import React, { FC, useEffect, useMemo, useState } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { RHELAutomaticSubscriptionData } from '@kubevirt-utils/hooks/useRHELAutomaticSubscription/utils/types';
 5	import { debounce } from '@kubevirt-utils/utils/debounce';
 6	import { Checkbox, Flex, Popover, PopoverPosition, Text, TextInput } from '@patternfly/react-core';
 7	import { HelpIcon } from '@patternfly/react-icons';
 8	
 9	import './automatic-subscription-custom-url.scss';
10	
11	type AutomaticSubscriptionCustomUrlProps = {
12	  customUrl: string;
13	  isDisabled: boolean;
14	  updateCustomUrl: (data: Partial<RHELAutomaticSubscriptionData>) => void;
15	};
16	
17	const AutomaticSubscriptionCustomUrl: FC<AutomaticSubscriptionCustomUrlProps> = ({
18	  customUrl,
19	  isDisabled,
20	  updateCustomUrl,
21	}) => {
22	  const { t } = useKubevirtTranslation();
23	  const [isChecked, setIsChecked] = useState<boolean>(!!customUrl);
24	  const [inputValue, setInputValue] = useState<string>();
25	  const debounceUpdateCustomUrl = useMemo(() => debounce(updateCustomUrl, 500), [updateCustomUrl]);
26	
27	  useEffect(() => {
28	    setInputValue(customUrl);
29	  }, [customUrl]);
30	
31	  return (
32	    <div className="AutomaticSubscriptionCustomUrl--main">
33	      <Flex alignItems={{ default: 'alignItemsCenter' }}>
34	        <Checkbox
35	          onChange={() =>
36	            setIsChecked((prevIsChecked) => {
37	              if (prevIsChecked) debounceUpdateCustomUrl({ customUrl: '' });
38	              return !prevIsChecked;
39	            })
40	          }
41	          className="AutomaticSubscriptionCustomUrl--checkbox"
42	          id="auto-register-rhel"
43	          isChecked={isChecked && !isDisabled}
44	          isDisabled={isDisabled}
45	          label={t('Use custom registration server url')}
46	        />
47	        <Popover
48	          aria-label={'Help'}
49	          bodyContent={t('Select this option if you use an on-premise subscription service')}
50	          position={PopoverPosition.right}
51	        >
52	          <HelpIcon />
53	        </Popover>
54	      </Flex>
55	      {isChecked && !isDisabled && (
56	        <Flex>
57	          <Text>URL</Text>
58	          <TextInput
59	            onChange={(_, value: string) => {
60	              setInputValue(value);
61	              debounceUpdateCustomUrl({ customUrl: value });
62	            }}
63	            className="AutomaticSubscriptionCustomUrl--input"
64	            value={inputValue}
65	          />
66	        </Flex>
67	      )}
68	    </div>
69	  );
70	};
71	
72	export default AutomaticSubscriptionCustomUrl;

